mapper.insert:
INSERT INTO question_tag (
    question_id,
    tag_name,
    sort_order
) VALUES (
    #{questionId},
    #{tagName},
    #{sortOrder}
)

mapper.select:
SELECT qt.tag_name, COUNT(DISTINCT qt.question_id) AS question_count FROM question_tag qt INNER JOIN question q ON q.id = qt.question_id WHERE q.status = 1 AND q.category_id IN
#{categoryId}
GROUP BY qt.tag_name ORDER BY question_count DESC, qt.tag_name ASC
